    public function createSeriesOccurrence(array $input,int $series_id,string $occurrence_key,string $local_date,bool $external_transaction=false,bool $locks_already_held=false):array
    {
        if($series_id<=0||!preg_match('/^\d{4}-\d{2}-\d{2}$/',$occurrence_key)||$occurrence_key!==$local_date){throw new \DomainException("gd_invalid_booking_series_occurrence");}
        $series=$this->db->table($this->db->prefixTable("gd_booking_series"))->select("id")->where("id",$series_id)->where("unit_id",$this->unit_id)->where("deleted",0)->get(1)->getRow();if(!$series){throw new \DomainException("gd_booking_series_not_found");}
