        try{if(!$locks_already_held){$locks->acquire($this->unit_id,$lock_ids);}if(!$existing){$seq=new SequenceService();$seq->ensure($this->unit_id,"booking","RES-".gmdate("Y")."-",6,true);$number=$seq->next($this->unit_id,"booking");}
            if(!$external_transaction){if($this->db->transBegin()===false){throw new \RuntimeException("booking transaction");}$in_tx=true;}if($existing){$fresh=$this->bookings->get_scoped($id,$this->unit_id);if(!$fresh||(int)$fresh->lock_version!==(int)$prepared["lock_version"]){throw new \DomainException("gd_booking_edit_conflict");}$existing=$fresh;}
            $this->assertResourcesCurrent($prepared["resources"]);$this->assertAvailable($prepared["resources"]);$this->assertNoDuplicate($prepared,$id);$conflict=$this->conflicts->findConflicts($this->unit_id,$prepared["resources"],$id?:null);if($conflict["has_conflict"]){throw new \DomainException("gd_booking_conflict");}
            $booking_data=$prepared["booking"];$booking_data["booking_number"]=$number;$booking_data["unit_id"]=$this->unit_id;if(!$existing&&$this->trusted_series_context!==null){$booking_data["source_type"]="booking_series";$booking_data["source_id"]=$this->trusted_series_context["series_id"];$booking_data+=$this->trusted_series_context+["is_series_exception"=>0,"detached_from_series"=>0];}$booking_data=$this->stamp($booking_data,!$existing);
            if($existing){unset($booking_data["unit_id"],$booking_data["booking_number"]);if(!$this->bookings->optimistic_update($id,$this->unit_id,(int)$prepared["lock_version"],$booking_data)){throw new \DomainException("gd_booking_edit_conflict");}$this->db->table($this->db->prefixTable("gd_booking_resources"))->where("booking_id",$id)->where("unit_id",$this->unit_id)->where("deleted",0)->update(["deleted"=>1,"updated_at"=>gmdate("Y-m-d H:i:s"),"updated_by"=>$this->actor_id?:null]);}
            else{$id=(int)$this->bookings->ci_save($booking_data);if($id<=0){throw new \RuntimeException("booking insert");}}
            foreach($prepared["resources"] as $resource){$data=$this->stamp(["unit_id"=>$this->unit_id,"booking_id"=>$id,"resource_id"=>$resource["resource_id"],"buffer_before_minutes"=>$resource["buffer_before_minutes"],"buffer_after_minutes"=>$resource["buffer_after_minutes"],"occupancy_starts_at_utc"=>$resource["occupancy_starts_at_utc"],"occupancy_ends_at_utc"=>$resource["occupancy_ends_at_utc"],"deleted"=>0],true);$this->booking_resources->ci_save($data);}
