            if(!$external_transaction){if($this->db->transCommit()===false){throw new \RuntimeException("booking commit");}$in_tx=false;}return ["id"=>$id,"booking_number"=>$number,"lock_version"=>$existing?(int)$prepared["lock_version"]+1:1];
