        $status=$existing?(string)$existing->status:trim((string)($input["status"]??""));if(!$existing&&!in_array($status,Constants::BOOKING_INITIAL_STATUSES,true)){throw new \DomainException("gd_invalid_booking_status");}if(!$existing&&$status==="confirmed"&&!$allow_confirmed){throw new \DomainException("gd_booking_status_permission_required");}
