    private function strictMinutes($value,int $max):int{$raw=(string)$value;if(!preg_match('/^\d+$/',$raw)){throw new \DomainException("gd_invalid_booking_buffer");}$n=(int)$raw;if($n>$max){throw new \DomainException("gd_invalid_booking_buffer");}return $n;}
    private function assertCustomerAndContact(string $type,int $customer,int $contact):void
    {
