        if($customer>0){$a=$this->db->table($this->db->prefixTable("gd_customer_accounts"))->where("id",$customer)->where("unit_id",$this->unit_id)->where("deleted",0)->where("status","active")->get(1)->getRow();if(!$a){throw new \DomainException("gd_invalid_booking_customer");}}
        if($contact>0){$p=$this->db->table($this->db->prefixTable("gd_people"))->where("id",$contact)->where("unit_id",$this->unit_id)->where("deleted",0)->get(1)->getRow();$linked=$this->db->table($this->db->prefixTable("gd_account_people"))->where("unit_id",$this->unit_id)->where("account_id",$customer)->where("person_id",$contact)->where("status","active")->where("deleted",0)->countAllResults();if(!$p||$linked<1){throw new \DomainException("gd_invalid_booking_contact");}}
    }
    private function assertResourcesCurrent(array $resources):void{$ids=array_column($resources,"resource_id");$rows=$this->db->table($this->db->prefixTable("gd_resources"))->select("id")->where("unit_id",$this->unit_id)->whereIn("id",$ids)->where("deleted",0)->where("is_active",1)->where("is_bookable",1)->get()->getResultArray();if(count($rows)!==count(array_unique($ids))){throw new \DomainException("gd_invalid_booking_resource");}}
