    private function assertAvailable(array $resources):void{$results=$this->physicalResults($resources);foreach($results as $result){if(empty($result["available"])){throw new \DomainException("gd_booking_resource_unavailable");}}}
    private function assertNoDuplicate(array $prepared,int $exclude):void
    {
        $b=$this->db->prefixTable("gd_bookings");$q=$this->db->table($b)->select("id,title,customer_account_id,status,hold_expires_at_utc")->where("unit_id",$this->unit_id)->where("deleted",0)->where("starts_at_utc",$prepared["booking"]["starts_at_utc"])->where("ends_at_utc",$prepared["booking"]["ends_at_utc"])->whereIn("status",Constants::BOOKING_BLOCKING_STATUSES);if($prepared["booking"]["customer_account_id"]===null){$q->where("customer_account_id IS NULL",null,false);}else{$q->where("customer_account_id",$prepared["booking"]["customer_account_id"]);}if($exclude){$q->where("id !=",$exclude);}$candidates=$q->get()->getResult();if(!$candidates){return;}$ids=[];foreach($candidates as $c){if($c->status==="hold"&&(string)$c->hold_expires_at_utc<=gmdate("Y-m-d H:i:s")){continue;}if(DataNormalizationService::name($c->title)===DataNormalizationService::name($prepared["booking"]["title"])){$ids[]=(int)$c->id;}}if(!$ids){return;}$br=$this->db->prefixTable("gd_booking_resources");$rows=$this->db->table($br)->select("booking_id,resource_id")->where("unit_id",$this->unit_id)->whereIn("booking_id",$ids)->where("deleted",0)->orderBy("resource_id")->get()->getResult();$by=[];foreach($rows as $r){$by[(int)$r->booking_id][]=(int)$r->resource_id;}$wanted=array_column($prepared["resources"],"resource_id");sort($wanted);foreach($by as $set){sort($set);if($set===$wanted){throw new \DomainException("gd_booking_duplicate");}}}
    private function bookingMetadata($value):?string{$json=DataNormalizationService::json($value,16000);if($json===null){return null;}$data=json_decode($json,true);$walk=function($v,$key="")use(&$walk){$lower=mb_strtolower((string)$key);foreach(["password","token","secret","authorization","cookie","price","amount","payment","charge","billing"] as $bad){if(str_contains($lower,$bad)){throw new \DomainException("gd_booking_metadata_forbidden");}}if(is_array($v)){foreach($v as $k=>$item){$walk($item,(string)$k);}}elseif(is_string($v)&&preg_match('/[<>]/',$v)){throw new \DomainException("gd_booking_metadata_forbidden");}};$walk($data);return $json;}
    private function configuredInt(string $key,int $default,int $min,int $max):int{$t=$this->db->prefixTable("gd_settings");$row=$this->db->table($t)->select("value")->where("key",$key)->where("deleted",0)->groupStart()->where("unit_id",$this->unit_id)->orWhere("unit_id IS NULL",null,false)->groupEnd()->orderBy("unit_id","DESC")->get(1)->getRow();$v=$row&&preg_match('/^\d+$/',(string)$row->value)?(int)$row->value:$default;return max($min,min($max,$v));}
    private function appendChangeEvents(int $id,object $before,array $old_resources,array $prepared):void{$after=$prepared["booking"];$old_ids=array_map(static fn($r)=>(int)$r->resource_id,$old_resources);$new_ids=array_column($prepared["resources"],"resource_id");if($before->starts_at_utc!==$after["starts_at_utc"]||$before->ends_at_utc!==$after["ends_at_utc"]){$this->events->append($id,"schedule_changed",$before->status,$before->status,null,["before"=>[$before->starts_at_utc,$before->ends_at_utc],"after"=>[$after["starts_at_utc"],$after["ends_at_utc"]]]);}if($old_ids!==$new_ids||json_encode(array_map(static fn($r)=>[(int)$r->buffer_before_minutes,(int)$r->buffer_after_minutes],$old_resources))!==json_encode(array_map(static fn($r)=>[$r["buffer_before_minutes"],$r["buffer_after_minutes"]],$prepared["resources"]))){$this->events->append($id,"resources_changed",$before->status,$before->status,null,["before"=>$old_ids,"after"=>$new_ids]);}if((int)$before->customer_account_id!==(int)$after["customer_account_id"]){$this->events->append($id,"customer_changed",$before->status,$before->status);}if((int)$before->contact_person_id!==(int)$after["contact_person_id"]){$this->events->append($id,"contact_changed",$before->status,$before->status);}}
